solution.code:
sealed class TrafficLight {
    data object Red : TrafficLight()
    data object Yellow : TrafficLight()
    data object Green : TrafficLight()
}

fun next(light: TrafficLight): TrafficLight = when (light) {
    is TrafficLight.Red    -> TrafficLight.Green
    is TrafficLight.Green  -> TrafficLight.Yellow
    is TrafficLight.Yellow -> TrafficLight.Red
}

